import{_ as n,c as a,o as p,b as l}from"./chunks/framework.DUr976bL.js";const u=JSON.parse('{"title":"OpenCV","description":"","frontmatter":{"title":"OpenCV","outline":"deep"},"headers":[{"level":2,"title":"概览","slug":"概览","link":"#概览","children":[]}],"relativePath":"aiart/deep-learning/opencv.md","filePath":"aiart/deep-learning/opencv.md"}'),e={name:"aiart/deep-learning/opencv.md"};function o(r,s,c,t,i,E){return p(),a("div",null,s[0]||(s[0]=[l(`<h1 id="opencv" tabindex="-1">OpenCV <a class="header-anchor" href="#opencv" aria-label="Permalink to &quot;OpenCV&quot;">​</a></h1><p>OpenCV(Open Source Computer Vision) is the world&#39;s biggest computer vision library.</p><p>OpenCV is open source, contains over 2500 algorithms, and is operated by the non-profit Open Source Vision Foundation. Since June 2000.</p><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><ul><li><p><strong>PyTorch ≈ 大脑</strong>（思考、学习、决策的核心）<br> 它负责“理解”图像内容：这是猫？这是车？目标物体在哪？姿态是什么？深度是多少？它能从数据中学习复杂的模式、泛化到没见过的情况、做端到端的预测。这是智能的“认知”部分。</p></li><li><p><strong>OpenCV ≈ 四肢 + 感官执行器</strong>（动手、感知、精细操作的工具箱）<br> 它负责：</p><ul><li>“眼睛”：读摄像头、读视频、读图片文件</li><li>“手”：resize、crop、颜色转换、归一化、letterbox、去畸变、画框、标注、alpha融合、图像拼接、实时显示</li><li>“基本反射”：传统快速算法（边缘检测、轮廓、透视变换、二值化、连通域、模板匹配、颜色阈值跟踪等），这些不需要“思考”，速度极快，适合实时前/后处理</li></ul></li></ul><div class="language-py line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">py</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#F97583;">import</span><span style="color:#E1E4E8;"> cv2</span></span>
<span class="line"><span style="color:#F97583;">import</span><span style="color:#E1E4E8;"> torch</span></span>
<span class="line"><span style="color:#F97583;">import</span><span style="color:#E1E4E8;"> numpy </span><span style="color:#F97583;">as</span><span style="color:#E1E4E8;"> np</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># OpenCV读图 + 预处理</span></span>
<span class="line"><span style="color:#E1E4E8;">img </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> cv2.imread(</span><span style="color:#9ECBFF;">&quot;test.jpg&quot;</span><span style="color:#E1E4E8;">)           </span><span style="color:#6A737D;"># BGR</span></span>
<span class="line"><span style="color:#E1E4E8;">img </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> cv2.cvtColor(img, cv2.</span><span style="color:#79B8FF;">COLOR_BGR2RGB</span><span style="color:#E1E4E8;">)   </span><span style="color:#6A737D;"># 转RGB</span></span>
<span class="line"><span style="color:#E1E4E8;">img_resized </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> cv2.resize(img, (</span><span style="color:#79B8FF;">640</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">640</span><span style="color:#E1E4E8;">))</span></span>
<span class="line"><span style="color:#E1E4E8;">img_tensor </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> torch.from_numpy(img_resized).permute(</span><span style="color:#79B8FF;">2</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">0</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">1</span><span style="color:#E1E4E8;">).float() </span><span style="color:#F97583;">/</span><span style="color:#79B8FF;"> 255.0</span></span>
<span class="line"><span style="color:#E1E4E8;">img_tensor </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> img_tensor.unsqueeze(</span><span style="color:#79B8FF;">0</span><span style="color:#E1E4E8;">).cuda()   </span><span style="color:#6A737D;"># [1,3,640,640]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># PyTorch模型推理</span></span>
<span class="line"><span style="color:#E1E4E8;">model </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> torch.load(</span><span style="color:#9ECBFF;">&quot;yolov11n.pt&quot;</span><span style="color:#E1E4E8;">)   </span><span style="color:#6A737D;"># 或 ultralytics 的 YOLO类</span></span>
<span class="line"><span style="color:#E1E4E8;">pred </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> model(img_tensor)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># OpenCV把结果画回原图</span></span>
<span class="line"><span style="color:#F97583;">for</span><span style="color:#E1E4E8;"> box </span><span style="color:#F97583;">in</span><span style="color:#E1E4E8;"> pred.boxes:</span></span>
<span class="line"><span style="color:#E1E4E8;">    x1,y1,x2,y2 </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> box.xyxy[</span><span style="color:#79B8FF;">0</span><span style="color:#E1E4E8;">].cpu().int().tolist()</span></span>
<span class="line"><span style="color:#E1E4E8;">    cv2.rectangle(img, (x1,y1), (x2,y2), (</span><span style="color:#79B8FF;">0</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">255</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">0</span><span style="color:#E1E4E8;">), </span><span style="color:#79B8FF;">2</span><span style="color:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">cv2.imshow(</span><span style="color:#9ECBFF;">&quot;result&quot;</span><span style="color:#E1E4E8;">, img)</span></span>
<span class="line"><span style="color:#E1E4E8;">cv2.waitKey(</span><span style="color:#79B8FF;">0</span><span style="color:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div>`,6)]))}const b=n(e,[["render",o]]);export{u as __pageData,b as default};
